/**
 * 誕生数別プールと共通プールを重み付きで選択する。
 *
 * 重み: 共通プール 70% / 誕生数別プール 30%
 * - 誕生数が 0（未入力）または該当プールが空の場合は共通プールにフォールバック。
 * - rng は呼び出し元から渡す（日ごとのシードで決定論的に動作）。
 *
 * @param rng - シード済みの乱数関数
 * @param base - 共通プール
 * @param byPath - 誕生数別プール
 * @param lpn - lifePathNumber（0 は未入力扱い）
 */
function selectDailyMessage(
  rng: () => number,
  base: string[],
  byPath: Record<number, string[]>,
  lpn: number,
): string {
  const pathPool = lpn !== 0 ? (byPath[lpn] ?? []) : [];
  const usePathPool = pathPool.length > 0 && rng() < 0.3;
  const pool = usePathPool ? pathPool : base;
  return pool[Math.floor(rng() * pool.length)] ?? base[0]!;
}

export function generateFortune(
  name: string,
  sign: string,
  gender: 'male' | 'female',
  _birthDay?: number,
  _birthMonth?: number,
): FortuneResult {
  const signIdx = SIGNS.findIndex((s) => s.k === sign);
  const bSeed = birthSeed(_birthDay, _birthMonth);
  const rng = makeSeededRandom(getDailySeed(signIdx * 100 + bSeed));
  const ranks: FortuneRank[] = ['大吉', '中吉', '小吉', '吉', '末吉'];
  const weights = [10, 25, 30, 25, 10];
  let r = rng() * 100;
  let acc = 0;
  let rank: FortuneRank = ranks[2]!;
  for (let i = 0; i < ranks.length; i++) {
    acc += weights[i]!;
    if (r < acc) {
      rank = ranks[i]!;
      break;
    }
  }
  const g = gender === 'male';
  const lpn = lifePathNumber(
    _birthDay ?? 0,
    _birthMonth ?? 0,
  );
  const lifePathMsg = LIFE_PATH_MESSAGES[lpn] ?? LIFE_PATH_MESSAGES[1]!;

  // NOTE: These literals reference `name` and `g`  -  must stay in this scope.
  const rankMsgsList: Record<FortuneRank, RankMessage[]> = {"大吉": [{summary: name+"さん、今日の流れ、年に数回レベル。「なんとなくうまくいく気がする」その感覚、今日は信じていい。直感に従って動いた分だけ、いい結果が来る日。", time: "夕方以降に大事なLINEが来る気配。今日は既読スルーしないで。", risk: "テンションが上がりすぎて余計な一言が出やすい日。特に深夜の投稿・メッセージは翌朝確認してから送って。"},{summary: name+"さん、今日は何をやっても「当たり」の日。選択肢で迷ったら「楽しそう」な方を選んで。論理より感覚を信じる日。", time: "出かける前の準備に時間をかけると吉。身だしなみが今日の運気を左右する。", risk: "調子が良すぎると油断が出る。財布とスマホは特に気をつけて。"},{summary: name+"さん、今日のあなた、ちょっとオーラが違う。周りの反応がいつもと変わるはず。その波に気づいたら、怖がらず乗って。", time: "起きてすぐの直感が一番正確。ふと浮かんだことをメモしておくと後で役に立つ。", risk: "期待されやすい日だから、引き受けすぎには気をつけて。「できます」は今日だけは慎重に。"},{summary: name+"さん、今日は「本音を言っても許される日」。いつも気を使いすぎてるなら、今日だけは自分の意見を出して。場の空気が不思議と受け入れてくれる。", time: "夜の時間帯が勝負。重要な話は夕方以降にするのがベスト。", risk: "いい日だからこそ、他人への配慮も忘れずに。「今日は運がいい」の油断が一番の敵。"},{summary: name+"さん、存在感が最大値の日。いるだけで場の雰囲気が変わる。自分では気づいてないかもしれないけど、周りはちゃんと見てる。", time: "動き出しの最初の1時間が黄金タイム。グズグズしないで、起きたら即行動。", risk: "目立つ日は嫉妬も生まれやすい。自慢話はほどほどに、でも堂々としてていい。"},{summary: name+"さん、後から「あの時動いてよかった」と思える日。気になってたこと、ずっと後回しにしてたこと、今日がそのタイミング。", time: "大事な人からの連絡、今日は即レスで。返信の速さが流れを変える。", risk: "ノリで約束しすぎないように。テンションで「いいよ！」と言った後で「え？」ってなる日。"},{summary: name+"さん、星が全力でプッシュしてる日。「私なんて」は今日だけ封印。自信がなくても行動した人が勝つ、それが今日のルール。", time: "誘いが来たら今日は乗って。断った先には何もないけど、受けた先には何かある。", risk: "全力で楽しんだ後の回復も計算に入れて。明日の自分に優しくしておくのが最高の1日の締め方。"},],"中吉": [{summary: name+"さん、今日は声がかかりやすい日。「ちょっといい？」から始まる話、全部乗ってみて。人とのやりとりの中に今日のいいことが潜んでる。", time: "目上の人からの評価が動くタイミング。いつも通りの丁寧さが今日は特に伝わる。", risk: "胃腸が弱めの日。食べすぎ注意。胃が重いと判断も鈍る。"},{summary: name+"さん、今日は「与えると倍で返ってくる日」。おごる、譲る、褒める。計算じゃなく自然体でやると、ちゃんと巡り巡って返ってくる。", time: "会話の中にチャンスが隠れてる。相手の話を聞くことに今日は集中して。", risk: "気前よくなりすぎて自分が損してない？出す前に自分の余裕を確認して。"},{summary: name+"さん、感覚が鋭い日。「なんかこの人いいな」「なんか違和感ある」 -  - その直感は今日特に当たってる。論理より体感を信じて。", time: "出かける前に少しだけ一人の時間を作って。整ってから動くと流れが変わる。", risk: "考えすぎると逆に判断が鈍る日。頭で10回悩むより、心で1回決めたほうが正解。"},{summary: name+"さん、小さないいことが重なる日。信号が全部青とか、タイミングがぴったり合うとか。「今日なんかいい」と思ったら、その流れに乗って。", time: "起きてからの数時間が集中力のピーク。この時間にやりたいことを片付けておくと後が楽になる。", risk: "いい波に乗ってる時こそ慢心しないで。謙虚さが次の運気を引き寄せる。"},{summary: name+"さん、「つながり」が強まる日。久しぶりに連絡したいと思ってた人、今日が正解のタイミング。向こうもあなたのこと考えてるかも。", time: "帰り道にうれしいことが潜んでる。いつもと少し違うルートを選んでみて。", risk: "「あとで返す」を今日だけはやめて。既読スルーが今日の信頼に直結する日。"},{summary: name+"さん、今日のあなたの話が面白い。いつもより言葉に引きつける力がある。会話を楽しんで、アイデアを声に出してみて。", time: "夜があなたの本領発揮タイム。一番大事なことはここで。", risk: "盛り上がりすぎると口が滑る日。「これ秘密なんだけど」は今日だけ我慢。"},{summary: name+"さん、今日は誰かの一言があなたの答えになる日。アンテナ高くして、人の話を聞いてみて。思わぬところにヒントが落ちてる。", time: "お風呂やシャワーの時間にアイデアが降ってくる。スマホを持ち込まず、頭を空っぽにして。", risk: "人の意見に流されすぎないように。参考にするのはいい、でも最後は自分で決めて。"},],"小吉": [{summary: name+"さん、派手さはないけど「なんかいい日だったな」と夜に思える日。小さな親切が積み重なって、じわじわ運気が上がってる。", time: "朝のうちに身の回りを片付けておくと、夜の流れがよくなる。やることは午前中に終わらせて。", risk: "SNSを見すぎると「自分だけ取り残されてる」モードに入りやすい日。通知を切って目の前のことに集中。"},{summary: name+"さん、今日は「丁寧に過ごす」が一番のいいスタート。コーヒーをちゃんと味わう、靴を揃える。そういう小さな積み重ねが今日の流れを作る。", time: "焦って決めるのは今日だけ避けて。「ちょっと待って」が使えるなら使う。", risk: "急ぎで決断すると裏目に出やすい日。「急かされてる感」があるときほど一呼吸入れて。"},{summary: name+"さん、今日はインプットの日。気になってた動画、記事、本 -  - 今日触れたものが来週以降のあなたを助ける。投資の日だと思って。", time: "夕方の集中力が高まってくる。気になってたことを調べたり、自分磨きに使うといい時間帯。", risk: "情報を入れすぎると頭がパンクする日。「もう十分」と思ったら散歩で切り替えて。"},{summary: name+"さん、地味にツイてる日。「あ、これ見つかった」「タイミングぴったり」って瞬間が来る。小さないいことを見逃さないで。", time: "午前中から動くとサクサク進む。夕方は流れに任せてOK。", risk: "「まあいっか」が多くなりやすい日。大事なことだけは先送りにしないで。"},{summary: name+"さん、今日は周りの優しさに気づける日。「ありがとう」を意識的に多く言ってみて。言葉は循環するから、巡り巡って自分に返ってくる。", time: "終わり際に小さないいことが。最後まで手を抜かないで。", risk: "自分を後回しにしがちな日。まず自分のご機嫌を取ってから、人のことを考えて。"},{summary: name+"さん、「あえてゆっくり」が今日は正解。焦って動くと空回りする。深呼吸して、自分のリズムで進めて。周りに合わせる必要はない。", time: "後半にいい流れが来る。前半は無理しないで省エネモードで。", risk: "周りのテンションに引っ張られて疲れやすい日。自分のペースは大切にしてね。"},{summary: name+"さん、身の回りを整えると運気が動く日。部屋の片付け、バッグの中の整理、財布の中身の確認。スッキリした空間がチャンスを呼ぶ。", time: "部屋を整えてから動くと、夜の流れが全然違う。まず10分だけ片付けから。", risk: "完璧にやろうとしすぎると結局何もできない日。「60点でいい」の精神で始めてみて。"},],"吉": [{summary: name+"さん、今日まいた種が2〜3週間後に実を結ぶ日。気になってた人に連絡する、行ってみたかった場所に行く -  - 小さな行動が未来を変える。", time: "夜遅くにいい流れが来る。終わり際まで気を抜かないで。", risk: "「なんか違う」と感じた直感、今日は特に正確。無理に合わせなくていい場面がある。"},{summary: name+"さん、「続ける」が今日のキーワードの日。地味に続けてきたことが、そろそろ形になり始めるサイン。やめないで、もう少しだけ。", time: "いつものルーティンがいつもより効く日。手順を丁寧にやるだけで結果が変わる。", risk: "今日は新しいことより、今あるものを磨くほうが吉。手を広げすぎると全部中途半端になる。"},{summary: name+"さん、小さな勇気が試される日。普段やらないことを一つだけやってみて。「できなかったらどうしよう」より「やったらどうなる？」で考えて。", time: "夜に決断の場面が来る。迷ったら「やる」を選んで。後悔するなら動いた後の後悔を選んで。", risk: "変化を恐れすぎると機会を逃す日。でも無茶はしなくていい。一歩だけでOK。"},{summary: name+"さん、今日は裏方が似合う日。目立つより支える側に回ると、後からちゃんと評価が来る。今日の頑張りは見えないけど、積み上がってる。", time: "前半は静かに準備して、夜から動くのがベスト。", risk: "手柄を横取りされそうでも今日は泳がせて。見てる人はちゃんと見てるから。"},{summary: name+"さん、整理の日。いらない人間関係、古いデータ、部屋のもの -  - 手放すと新しいものが入ってくるスペースができる。今日はデトックスday。", time: "夕方から頭がクリアになってくる。エンジンがかかってからが本番。", risk: "勢いで大事なものまで捨てないように。「迷ったら取っておく」が今日のルール。"},{summary: name+"さん、目に見えない資産が育ってる日。健康、信頼、スキル -  - 今日の地味な行動が半年後に大きく効いてくる。派手さはないけど着実に積み上がっているかも。", time: "早めに動くほど吉。夕方までの行動のリターンが一番大きい。", risk: "華やかさを求めると空振りする日。地道が最強。"},{summary: name+"さん、「待つ力」が試される日。焦って動くより、相手のタイミングを待つほうがうまくいく。我慢は今日だけの投資だと思って。", time: "帰宅後に嬉しい知らせが届く予感。こまめにスマホをチェックして。", risk: "催促したくなっても今日はグッと堪えて。急かすと逆効果になる日。"},],"末吉": [{summary: name+"さん、今日は「静」の日。お風呂にゆっくり浸かって、好きなものを食べて、早めに寝る。それが今日の最強行動。無理して動くと来週にツケが来る。", time: "起きてからしばらくは省エネモードで。夕方にエネルギーが戻ってくるから焦らないで。", risk: "今日の疲れは本物。「気のせい」じゃなくて体と心が休息を求めてる。聞いてあげて。"},{summary: name+"さん、頑張らなくていい日。「生きてるだけで偉い」が今日のあなたには一番正確な言葉。自分を責めてるなら、それは運気のせい。あなたは悪くない。", time: "夕方まではゆっくりペースで。夜には少し気力が戻ってくる。", risk: "完璧を目指さないで。今日の60点は他の日の120点に値する。"},{summary: name+"さん、空白の時間を作ってみて。予定を入れない、ぼーっとする贅沢。何もしない時間から生まれるものが今日はある。", time: "帰宅後の時間が一番頭がクリア。その時間に浮かんだことをメモして。", risk: "無理にテンションを上げようとすると、余計に疲れる日。ローテンションの自分を許してあげて。"},{summary: name+"さん、嵐の前の静けさ日。明日以降に運気が上がってくるから、今日はしっかり充電しておいて。休んだ分だけ、次に全力で動ける。", time: "朝のうちに済ませられることは済ませておくと楽になる。用事はまとめて早めに。", risk: "大事な決断は今日じゃなくていい。先送りが正解な珍しい日。"},{summary: name+"さん、内省の日。最近モヤモヤしてることを、紙に書き出してみて。書くだけで半分は解決する。頭の中のノイズを外に出して整理する日。", time: "起きてすぐが一番頭がクリア。大事な考え事はこのタイミングで。", risk: "人に相談するのは明日以降がいい。今日は自分の中で温める日。"},{summary: name+"さん、守りの日。攻めなくていい。現状維持が今日の最適解。今あるものを大切にすることが、明日の自分への贈り物。", time: "夕方の静かな時間が一番穏やか。その時間を大事にして。", risk: "新しいことを始めるには向かない日。計画を立てるだけならOK。実行は来週からにして。"},{summary: name+"さん、五感を大事にして。美味しいもの、いい香り、肌触りのいい服 -  - 体を喜ばせることが今日のいいスタート。頭じゃなくて体が先に答えを知ってる日。", time: "夕方は感覚が敏感になる。スキンケアやヘアケアの効果が出やすい時間帯。", risk: "頭で考えすぎると沼にはまる日。今日は体の声を信じて動いて。"},],} as Record<FortuneRank, RankMessage[]>;

  const signPersonality: Record<string, SignPersonality> = {おひつじ座:{trait:"あなたは今、「このままじゃダメだ」って焦りと戦ってるはず。行動力はあるのに、どこに向かえばいいか分からない。",love:g?"好きになったら一気に距離を詰めるタイプ。でも相手が引いたら急に冷めちゃう。今回は1テンポ待って。":"「待つ恋」が苦手。でも今月は追いかけるより追いかけさせるほうがうまくいく。",work:"競争心が燃えてるけど、ライバルは他人じゃなくて昨日の自分。比較をやめた瞬間、本当の力が出る。",health:"頭痛・首の凝りが出やすい時期。アドレナリンが出すぎてる。意識的にクールダウンの時間を。"},おうし座:{trait:"あなたは今、「変わらなきゃ」と「変わりたくない」の間で揺れてるはず。安定を愛するあなたにとって、変化は脅威。でも心のどこかでは分かってる。",love:g?"一度決めたら揺るがない。でもその頑固さが相手を窮屈にしてない？愛情表現、最近してる？":"「居心地のいい関係」を求めすぎて、刺激のある出会いを避けてない？今月は少し冒険してみて。",work:"コツコツ積み上げてきたものが評価される時期。ただし「いつも通り」だけだと天井が見える。一つだけ新しいことを混ぜて。",health:"喉と甲状腺に注意。言いたいことを飲み込みすぎてない？声を出す（歌でもOK）だけで体が軽くなる。"},ふたご座:{trait:"あなたは今、頭の回転が速すぎて自分でも追いつけてない状態。選択肢が多すぎて決められない。でもそれは「どれも良い」ってことの裏返し。",love:g?"会話が面白い人に惹かれるけど、話が合う＝相性がいいとは限らない。言葉の裏にある誠実さを見て。":"「飽きるかも」って不安がある？それは相手の問題じゃなくて、あなたの中の好奇心が満たされてないだけ。二人で新しい体験を。",work:"マルチタスクが得意だけど、今は一つに集中するほうが結果が出る。器用にいろんなことをこなせるからこそ、今は一つに絞ると一気に伸びるチャンス。",health:"手首・肩・呼吸器が弱い時期。スマホの使いすぎに注意。1時間に1回、深呼吸3回。"},かに座:{trait:"あなたは今、誰かを守りたい気持ちと自分を守りたい気持ちの間で消耗してるはず。優しさが自分を傷つけてることに気づいて。",love:g?"「俺がいないとダメだ」って思ってない？それは愛じゃなくて支配。相手の自立を応援できる強さを。":"相手の機嫌で自分の気分が左右されてない？それは優しさの証拠だけど、自分の気持ちも大切にして。あなたの感情を取り戻して。",work:"チームの空気を読みすぎて本音が言えない。でもあなたの意見がチームを救う場面が今週ある。勇気を出して。",health:"胃腸が弱ってる。ストレスが直接お腹に来るタイプ。温かい飲み物と、寝る前の5分の腹式呼吸。"},しし座:{trait:"あなたは今、「認めてほしい」と「認めてほしいと思ってる自分が嫌」の間にいるはず。プライドが邪魔して素直になれない時期。",love:g?"「俺を見て」が強すぎると相手が疲れる。今月は相手を輝かせる側に回ってみて。意外とそっちのほうがモテる。":"褒められると嬉しいけど、お世辞は見抜ける。本気であなたの内面を見てくれる人を選んで。",work:"リーダーシップが求められる場面が増える。ただし「俺についてこい」より「一緒に行こう」のほうが今は効く。",health:"心臓と背中に負担がかかりやすい。姿勢を正すだけで自信とエネルギーが戻る。胸を張って。"},おとめ座:{trait:"あなたは今、「もっとちゃんとしなきゃ」で自分を追い詰めてるはず。完璧を目指すのは素晴らしいけど、完璧じゃない自分も許してあげて。",love:g?"相手の欠点が気になりすぎてない？理想のチェックリストを捨てて、一緒にいる時の「感覚」を信じて。":"「ちゃんとしてない自分は愛されない」って思ってない？ありのままで愛される経験が、あなたの人生を変える。",work:"分析力と正確さが光る時期。ただし細部にこだわりすぎて全体を見失わないで。完成度80%で出す練習を。",health:"腸内環境が運気に直結する時期。発酵食品を意識的に。あと、考えすぎて眠れない夜は書き出すことで解消。"},てんびん座:{trait:"あなたは今、誰かのバランスを取ることに疲れてるはず。「どっちも大事」は優しさだけど、それは「自分を後回しにしてる」の別名。",love:g?"「合わせすぎてる自分」に気づいて。本当の相性は、意見がぶつかった時に試される。":"いい人止まりになってない？好かれようとするより、自分の好きを優先したほうが魅力的。",work:"調整役として重宝されるけど、それだけじゃ上にはいけない。自分の主張を通す場面を意識的に作って。",health:"腰と腎臓に注意。バランスを取ろうとしすぎて体にも歪みが出てる。ストレッチと水分補給。"},さそり座:{trait:"あなたは今、表面は完璧にコントロールしてるけど、内側で激しい感情が渦巻いてるはず。全部抱え込まなくていい。信頼できる一人に話してみて。",love:g?"好きになったら底なし。でもその深さが重いと感じる相手もいる。「全部を見せなくていい」が今月のテーマ。":"「この人は本物か」テストし続けてない？試される側の気持ちも考えて。信じる覚悟が恋を本物にする。",work:"洞察力が最強な時期。他人が見落としてるリスクや本音が手に取るように分かる。その力を建設的に使って。",health:"生殖器系とホルモンバランスに注意。感情を溜め込みすぎると体に出る。泣きたい時は泣いて。"},いて座:{trait:"あなたは今、「もっと面白いことがあるはず」って退屈と戦ってるはず。ルーティンが窮屈で、何かを壊したくなってる。",love:g?"「束縛しないでほしい」は分かるけど、自由すぎると相手は不安になる。たまには安心感をあげて。":"旅先の恋に憧れるタイプ。でも日常を一緒に楽しめる人のほうが長続きする。刺激と安定のバランスを。",work:"新規プロジェクトや挑戦に縁がある時期。ただしスタートダッシュだけで終わらせないで。やり切る力が今の課題。",health:"太ももと肝臓に注意。お酒の量を今月だけ半分にしてみて。驚くほど頭がクリアになるから。"},やぎ座:{trait:"あなたは今、「頑張ってるのに報われない」と感じてるはず。でもそれは成果が出るまでのタイムラグ。種はもう撒いてある。あと少し。",love:g?"仕事を優先しすぎて大切な人を放置してない？「忙しい」は言い訳にならない。今日5分だけ、全集中で向き合って。":"「しっかりしてるね」って言われるのは嬉しいけど、たまには甘えてみて。弱さを見せることも強さ。",work:"評価・報酬に動きがある時期。ただし「もらう」前に「与える」を意識して。見返り度外視の行動が結果的に最大リターンを生む。",health:"膝・関節・骨に注意。カルシウムとビタミンD意識して。あとストレスで歯を食いしばってない？寝る前にマウスピースか、顎のマッサージ。"},みずがめ座:{trait:"あなたは今、「みんなと同じ」が生理的に無理な時期。周りに合わせようとすると体調まで崩れる。もう無理に合わせなくていい。",love:g?"「変わってるね」が最高の褒め言葉。そんなあなたを面白がってくれる人が本物のパートナー。":"友達以上恋人未満が多くない？知的な繋がりは大事だけど、たまには理屈抜きで「好き」を認めてあげて。",work:"革新的なアイデアが降りてくる時期。ただし「画期的すぎて理解されない」パターンに注意。伝え方を工夫すれば通る。",health:"足首とふくらはぎが弱い時期。血行不良に注意。着圧ソックスか、寝る前のふくらはぎマッサージが効く。"},うお座:{trait:"あなたは今、現実と空想の境目が曖昧になりかけてるはず。それは感受性が高まってる証拠。でも地に足をつける時間も必要。",love:g?"相手に夢を見すぎてない？理想化した相手と目の前の生身の相手は別人。ギャップに幻滅する前に、現実の良さを探して。":"「この人を助けてあげたい」が恋の始まりになりがち。でもお互いが自立した関係の方がうまくいくよ。対等な関係を意識して。",work:"クリエイティブな仕事で力を発揮する時期。ただし締め切りや数字の管理は苦手が出やすい。得意な人に任せる勇気。",health:"足裏とリンパに注意。むくみやすい時期。足湯が最強。寝る前の10分だけでも効く。"}};

  const dailyRng0 = makeSeededRandom(getDailySeed(signIdx * 13 + 777 + bSeed));
  const rmList = rankMsgsList[rank] || rankMsgsList['吉']!;
  const rm = rmList[Math.floor(dailyRng0() * rmList.length)]!;
  const personality = signPersonality[sign] || signPersonality['おひつじ座']!;
  const charSet = SIGN_GENDER_CHAR[sign];
  const charId = charSet ? (g ? charSet.male : charSet.female) : 'yume_kobuta';
  const bestType = DREAM_TYPES.find((t) => t.id === charId) || DREAM_TYPES[0]!;
  // 誕生数別プール 30% / 共通プール 70% の重み抽選。
  // selectDailyMessage 内で rng() を2回消費するため、カテゴリごとに独立したシードを使う。
  const dailyRngLove = makeSeededRandom(getDailySeed(signIdx * 31 + 500 + bSeed));
  const dailyRngWork = makeSeededRandom(getDailySeed(signIdx * 31 + 600 + bSeed));
  const dailyRngHealth = makeSeededRandom(getDailySeed(signIdx * 31 + 700 + bSeed));
  const dailyLove = selectDailyMessage(dailyRngLove, DAILY_LOVE_BASE, DAILY_LOVE_BY_PATH, lpn);
  const dailyWork = selectDailyMessage(dailyRngWork, DAILY_WORK_BASE, DAILY_WORK_BY_PATH, lpn);
  const dailyHealth = selectDailyMessage(dailyRngHealth, DAILY_HEALTH_BASE, DAILY_HEALTH_BY_PATH, lpn);

  return {
    rank,
    summary: rm.summary,
    time: rm.time,
    risk: rm.risk,
    personality,
    lucky: generateLucky(signIdx),
    sign,
    type: bestType,
    dailyLove,
    dailyWork,
    dailyHealth,
    lifePathMessage: lifePathMsg,
  };
}
